// Script Continued Below
var MarkInactiveConditionalMethods = Class.create();
MarkInactiveConditionalMethods.prototype = {
//	tcs: new TaskerCommonScriptingMethods(),
	initialize: function() {
	},
	checkOrgHierarchyPermission: function(sOUID) {
		var answer = false;
		var userInfoScripts = new UserInfoScripts();
		// STRY0050440 DFCT0011930
		var isUserGHAforOU = userInfoScripts.userIsOrgAdminForOU(sOUID);
		var isUserOUAdminforOU = userInfoScripts.IsUserOUAdministrator(sOUID, gs.getUserID());
		answer = isUserGHAforOU || isUserOUAdminforOU;

		return answer;

	},
	checkTaskPermission: function(current) {
      	var answer = false;
		var userId = gs.getUser().getID();
		var reviewer = current.getValue("u_reviewer");
		var ou = current.getValue("primary_assignee");
		// DFCT0011930
		var userInfoScripts = new UserInfoScripts();
		var isUserTaskManagerforOU = userInfoScripts.IsUserTaskingAuthority(ou, userId);
      	var isUserTaskAdministratorforOU = userInfoScripts.userIsTaskAdministratorForOU(ou);
		var isUserReviewer = userId == reviewer;

		answer = isUserReviewer || isUserTaskManagerforOU || isUserTaskAdministratorforOU;
		return answer;
	},
	type: 'MarkInactiveConditionalMethods'
};
